import { usePluginData, type PluginPageProps, type PluginSidebarProps, type PluginWidgetProps } from "@paperclipai/plugin-sdk/ui";
import { useState, type CSSProperties } from "react";
import { COLUMN_UNASSIGNED, PAGE_ROUTE } from "../constants.js";
import type { BoardIssueCard, MissionCard, WorkBoardSnapshot } from "../worker.js";

const pageStyle: CSSProperties = {
  display: "grid",
  gap: "24px",
  padding: "24px",
};

const heroStyle: CSSProperties = {
  display: "grid",
  gap: "16px",
  padding: "24px",
  borderRadius: "24px",
  border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 85%, transparent)",
  background: [
    "radial-gradient(circle at top left, color-mix(in srgb, var(--accent, #7dd3fc) 30%, transparent) 0%, transparent 42%)",
    "linear-gradient(145deg, color-mix(in srgb, var(--card, #ffffff) 96%, transparent), color-mix(in srgb, var(--background, #f8fafc) 92%, transparent))",
  ].join(", "),
  boxShadow: "0 24px 80px rgba(15, 23, 42, 0.06)",
};

const metricsGridStyle: CSSProperties = {
  display: "grid",
  gap: "12px",
  gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
};

const metricCardStyle: CSSProperties = {
  display: "grid",
  gap: "6px",
  padding: "14px 16px",
  borderRadius: "18px",
  border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 72%, transparent)",
  background: "color-mix(in srgb, var(--card, #ffffff) 92%, transparent)",
};

const boardGridStyle: CSSProperties = {
  display: "grid",
  gap: "18px",
  gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
  alignItems: "start",
};

const columnStyle: CSSProperties = {
  display: "grid",
  gap: "14px",
  padding: "18px",
  borderRadius: "22px",
  border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 78%, transparent)",
  background: "color-mix(in srgb, var(--card, #ffffff) 96%, transparent)",
  boxShadow: "0 18px 48px rgba(15, 23, 42, 0.05)",
};

const missionCardStyle: CSSProperties = {
  display: "grid",
  gap: "10px",
  padding: "14px",
  borderRadius: "16px",
  border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 75%, transparent)",
  background: "color-mix(in srgb, var(--background, #f8fafc) 78%, var(--card, #ffffff))",
};

const bucketSectionStyle: CSSProperties = {
  display: "grid",
  gap: "8px",
};

const bucketHeaderButtonStyle: CSSProperties = {
  display: "flex",
  alignItems: "center",
  justifyContent: "space-between",
  gap: "8px",
  width: "100%",
  border: "none",
  padding: 0,
  background: "transparent",
  cursor: "pointer",
  textAlign: "left",
  color: "inherit",
};

const issueCardStyle: CSSProperties = {
  display: "grid",
  gap: "8px",
  padding: "10px 12px",
  borderRadius: "12px",
  border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 75%, transparent)",
  background: "color-mix(in srgb, var(--card, #ffffff) 90%, transparent)",
};

const tinyMutedStyle: CSSProperties = {
  fontSize: "12px",
  color: "color-mix(in srgb, var(--foreground, #0f172a) 62%, transparent)",
  lineHeight: 1.45,
};

const anchorResetStyle: CSSProperties = {
  color: "inherit",
  textDecoration: "none",
};

function hostPath(companyPrefix: string | null | undefined, suffix: string): string {
  return companyPrefix ? `/${companyPrefix}${suffix}` : suffix;
}

function pluginPagePath(companyPrefix: string | null | undefined): string {
  return hostPath(companyPrefix, `/${PAGE_ROUTE}`);
}

function issuePath(companyPrefix: string | null | undefined, issue: BoardIssueCard): string {
  const pathId = issue.identifier ?? issue.id;
  return hostPath(companyPrefix, `/issues/${pathId}`);
}

function formatDateTime(value: string | null): string {
  if (!value) return "-";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return "-";
  return new Intl.DateTimeFormat("ko-KR", {
    timeZone: "Asia/Seoul",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  }).format(parsed);
}

function relativeAgeLabel(days: number): string {
  if (days <= 0) return "오늘 갱신";
  if (days === 1) return "1일 경과";
  return `${days}일 경과`;
}

function useWorkBoard(companyId: string | null | undefined) {
  return usePluginData<WorkBoardSnapshot>("work-board-overview", {
    companyId: companyId ?? "",
  });
}

function MetricCard({ label, value, helper, accent }: { label: string; value: string | number; helper: string; accent?: string }) {
  return (
    <div style={metricCardStyle}>
      <div style={tinyMutedStyle}>{label}</div>
      <strong style={{ fontSize: "24px", lineHeight: 1, color: accent || "inherit" }}>{value}</strong>
      <div style={tinyMutedStyle}>{helper}</div>
    </div>
  );
}

function IssueTile({ companyPrefix, issue }: { companyPrefix: string | null | undefined; issue: BoardIssueCard }) {
  return (
    <a href={issuePath(companyPrefix, issue)} style={anchorResetStyle}>
      <article style={issueCardStyle}>
        <div style={{ display: "flex", justifyContent: "space-between", gap: "8px", alignItems: "center" }}>
          <strong style={{ fontSize: "13px" }}>{issue.identifier ?? issue.id.slice(0, 8)}</strong>
          <span style={{ ...tinyMutedStyle, whiteSpace: "nowrap" }}>{issue.statusLabel}</span>
        </div>
        <div style={{ fontSize: "14px", lineHeight: 1.45 }}>{issue.title}</div>
        <div style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
          <span style={{ ...tinyMutedStyle, padding: "2px 8px", borderRadius: "999px", background: "color-mix(in srgb, var(--muted, #e5e7eb) 58%, transparent)" }}>
            {issue.priority}
          </span>
          {issue.overdueFromLastWeek ? (
            <span style={{ ...tinyMutedStyle, padding: "2px 8px", borderRadius: "999px", background: "color-mix(in srgb, #ef4444 16%, transparent)", color: "#991b1b" }}>
              overdue
            </span>
          ) : null}
          {issue.stale ? (
            <span style={{ ...tinyMutedStyle, padding: "2px 8px", borderRadius: "999px", background: "color-mix(in srgb, #f59e0b 16%, transparent)", color: "#92400e" }}>
              stale
            </span>
          ) : null}
        </div>
        <div style={tinyMutedStyle}>
          {issue.status === "done"
            ? `완료 ${formatDateTime(issue.completedAt)}`
            : `${relativeAgeLabel(issue.ageDays)} · 업데이트 ${formatDateTime(issue.updatedAt)}`}
        </div>
      </article>
    </a>
  );
}

function bucketAccent(key: string) {
  if (key === "delayed") {
    return { color: "#ef4444", background: "color-mix(in srgb, #ef4444 10%, transparent)" };
  }
  if (key === "waiting") {
    return { color: "#f59e0b", background: "color-mix(in srgb, #f59e0b 10%, transparent)" };
  }
  if (key === "inProgress") {
    return { color: "#3b82f6", background: "color-mix(in srgb, #3b82f6 10%, transparent)" };
  }
  return { color: "#22c55e", background: "color-mix(in srgb, #22c55e 10%, transparent)" };
}

function MissionBucketSection({
  bucket,
  companyPrefix,
}: {
  bucket: MissionCard["buckets"][number];
  companyPrefix: string | null | undefined;
}) {
  const [collapsed, setCollapsed] = useState(bucket.count === 0);
  const accent = bucketAccent(bucket.key);

  return (
    <section
      style={{
        ...bucketSectionStyle,
        padding: "10px 12px",
        borderRadius: "12px",
        borderLeft: `3px solid ${accent.color}`,
        background: accent.background,
      }}
    >
      <button type="button" style={bucketHeaderButtonStyle} onClick={() => setCollapsed((value) => !value)}>
        <span style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <span aria-hidden="true" style={{ width: "8px", height: "8px", borderRadius: "999px", background: accent.color }} />
          <strong style={{ fontSize: "13px" }}>{bucket.label}</strong>
        </span>
        <span style={{ ...tinyMutedStyle, display: "flex", alignItems: "center", gap: "8px" }}>
          <span>{bucket.count}건</span>
          <span aria-hidden="true">{collapsed ? "▸" : "▾"}</span>
        </span>
      </button>

      {!collapsed ? bucket.items.length > 0 ? bucket.items.map((item) => (
        <IssueTile key={item.id} companyPrefix={companyPrefix} issue={item} />
      )) : (
        <div style={{ ...tinyMutedStyle, padding: "8px 10px", borderRadius: "10px", background: "color-mix(in srgb, var(--muted, #e5e7eb) 38%, transparent)" }}>
          비어 있음
        </div>
      ) : null}
    </section>
  );
}

function MissionCardPanel({ mission, companyPrefix }: { mission: MissionCard; companyPrefix: string | null | undefined }) {
  const [expanded, setExpanded] = useState(false);
  const totalTasks = mission.progress.total;

  return (
    <article style={missionCardStyle}>
      <button
        type="button"
        onClick={() => setExpanded((v) => !v)}
        style={{ all: "unset", cursor: "pointer", display: "grid", gap: "6px", width: "100%" }}
      >
        <div style={{ display: "flex", justifyContent: "space-between", gap: "10px", alignItems: "start" }}>
          <div style={{ display: "grid", gap: "4px", textAlign: "left" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
              <span aria-hidden="true" style={{ fontSize: "12px", opacity: 0.6 }}>{expanded ? "▾" : "▸"}</span>
              <strong style={{ fontSize: "16px" }}>{mission.title}</strong>
            </div>
            <div style={tinyMutedStyle}>
              {mission.missionIdentifier ?? mission.missionIssueId ?? mission.missionId.slice(0, 8)}
              {" · "}{totalTasks}건
            </div>
          </div>
          <span style={{ ...tinyMutedStyle, padding: "4px 8px", borderRadius: "999px", background: "color-mix(in srgb, var(--accent, #7dd3fc) 16%, transparent)" }}>
            {mission.progress.done}/{mission.progress.total}
          </span>
        </div>

        <div style={{ display: "grid", gap: "4px" }}>
          <div style={{ width: "100%", height: "6px", borderRadius: "999px", background: "color-mix(in srgb, var(--muted, #e5e7eb) 60%, transparent)", overflow: "hidden" }}>
            <div
              style={{
                width: `${mission.progress.percent}%`,
                height: "100%",
                borderRadius: "999px",
                background: mission.progress.percent === 100 ? "#22c55e" : "linear-gradient(90deg, #22c55e, #0ea5e9)",
              }}
            />
          </div>
        </div>
      </button>

      {expanded ? (
        <div style={{ display: "grid", gap: "8px", marginTop: "8px" }}>
          {mission.buckets.map((bucket) => (
            <MissionBucketSection key={bucket.key} bucket={bucket} companyPrefix={companyPrefix} />
          ))}
        </div>
      ) : null}
    </article>
  );
}

function UnassignedSection({
  missions,
  companyPrefix,
}: {
  missions: MissionCard[];
  companyPrefix: string | null | undefined;
}) {
  const allItems = missions.flatMap((m) => m.buckets.flatMap((b) => b.items));
  if (allItems.length === 0) return null;

  return (
    <section style={{ ...columnStyle, gridColumn: "1 / -1" }}>
      <div style={{ display: "flex", justifyContent: "space-between", gap: "8px", alignItems: "center" }}>
        <strong style={{ fontSize: "15px", opacity: 0.6 }}>미분류</strong>
        <span style={{ ...tinyMutedStyle, padding: "4px 8px", borderRadius: "999px", background: "color-mix(in srgb, var(--muted, #e5e7eb) 52%, transparent)" }}>
          {allItems.length}건
        </span>
      </div>
      <div style={{ display: "flex", gap: "8px", flexWrap: "wrap" }}>
        {allItems.map((item) => (
          <IssueTile key={item.id} companyPrefix={companyPrefix} issue={item} />
        ))}
      </div>
    </section>
  );
}

function ColumnPanel({
  name,
  missions,
  companyPrefix,
  isUnassigned,
}: {
  name: string;
  missions: MissionCard[];
  companyPrefix: string | null | undefined;
  isUnassigned?: boolean;
}) {
  if (isUnassigned) {
    return <UnassignedSection missions={missions} companyPrefix={companyPrefix} />;
  }

  return (
    <section style={columnStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", gap: "8px", alignItems: "center" }}>
        <strong style={{ fontSize: "17px" }}>{name}</strong>
        <span style={{ ...tinyMutedStyle, padding: "4px 8px", borderRadius: "999px", background: "color-mix(in srgb, var(--muted, #e5e7eb) 52%, transparent)" }}>
          {missions.length} 미션
        </span>
      </div>

      {missions.length > 0 ? missions.map((mission) => (
        <MissionCardPanel key={mission.missionId} mission={mission} companyPrefix={companyPrefix} />
      )) : (
        <div style={tinyMutedStyle}>표시할 미션이 없습니다.</div>
      )}
    </section>
  );
}

function BoardContent({
  context,
  data,
  onRefresh,
  loading,
}: {
  context: PluginPageProps["context"];
  data: WorkBoardSnapshot;
  onRefresh: () => void;
  loading: boolean;
}) {
  return (
    <div style={pageStyle}>
      <section style={heroStyle}>
        <div style={{ display: "grid", gap: "8px" }}>
          <div style={{ ...tinyMutedStyle, textTransform: "uppercase", letterSpacing: "0.08em" }}>mission-first board</div>
          <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
            <h1 style={{ margin: 0, fontSize: "clamp(28px, 4vw, 42px)", lineHeight: 1.02 }}>
              금주 미션 보드
            </h1>
            <button
              type="button"
              onClick={onRefresh}
              disabled={loading}
              style={{
                padding: "8px 16px",
                borderRadius: "12px",
                border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 72%, transparent)",
                background: "color-mix(in srgb, var(--card, #ffffff) 92%, transparent)",
                cursor: loading ? "wait" : "pointer",
                fontSize: "13px",
                color: "inherit",
                opacity: loading ? 0.5 : 1,
              }}
            >
              {loading ? "갱신 중..." : "↻ 새로고침"}
            </button>
          </div>
          <div style={{ fontSize: "15px", lineHeight: 1.6, maxWidth: "760px" }}>
            parent issue를 미션으로 보고 하위 이슈를 그룹화합니다. 하위 라벨이 없으면 부모 라벨을 상속해 칼럼에 배치합니다.
          </div>
        </div>

        <div style={metricsGridStyle}>
          <MetricCard label="미션 수" value={data.columns.filter((c) => c.key !== COLUMN_UNASSIGNED).reduce((sum, c) => sum + c.missionCount, 0)} helper="이번 주 추적 중인 미션 (미분류 제외)" accent="#0ea5e9" />
          <MetricCard label="대기" value={data.totals.todo} helper="대기 중인 태스크" accent="#f59e0b" />
          <MetricCard label="진행" value={data.totals.inProgress} helper="진행 중인 태스크" accent="#3b82f6" />
          <MetricCard label="지연" value={data.totals.overdue} helper="N일 이상 미처리" accent="#ef4444" />
        </div>
      </section>

      <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "center", flexWrap: "wrap" }}>
        <div style={tinyMutedStyle}>{data.weekRange.label}</div>
        <a href={pluginPagePath(context.companyPrefix)} style={{ ...anchorResetStyle, ...tinyMutedStyle }}>
          route: {pluginPagePath(context.companyPrefix)}
        </a>
      </div>

      <section style={boardGridStyle}>
        {data.columns.filter((c) => c.key !== COLUMN_UNASSIGNED).map((column) => (
          <ColumnPanel key={column.key} name={column.name} missions={column.missions} companyPrefix={context.companyPrefix} />
        ))}
      </section>

      {data.columns.filter((c) => c.key === COLUMN_UNASSIGNED).map((column) => (
        <ColumnPanel key={column.key} name={column.name} missions={column.missions} companyPrefix={context.companyPrefix} isUnassigned />
      ))}
    </div>
  );
}

function WorkBoardHelpSection() {
  const [showHelp, setShowHelp] = useState(false);

  return (
    <div style={{ ...pageStyle, paddingTop: 0 }}>
      <section style={columnStyle}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <strong style={{ fontSize: "17px" }}>Help</strong>
          <button
            type="button"
            onClick={() => setShowHelp(!showHelp)}
            style={{
              padding: "8px 16px",
              borderRadius: "12px",
              border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 72%, transparent)",
              background: "color-mix(in srgb, var(--card, #ffffff) 92%, transparent)",
              cursor: "pointer",
              fontSize: "13px",
              color: "inherit",
            }}
          >
            {showHelp ? "닫기" : "도움말"}
          </button>
        </div>
        {showHelp && (
          <div style={tinyMutedStyle}>
            <p style={{ ...tinyMutedStyle, fontWeight: 600, fontSize: "14px", marginBottom: "8px" }}>Mission Board 도움말</p>

            <p style={{ ...tinyMutedStyle, fontWeight: 600, marginTop: "12px" }}>기본 개념</p>
            <ul style={{ margin: "4px 0", paddingLeft: "20px" }}>
              <li>에이전트별 이슈를 칸반 보드로 시각화</li>
              <li>상태별 분류: 지연 / 대기 / 진행 / 완료</li>
            </ul>

            <p style={{ ...tinyMutedStyle, fontWeight: 600, marginTop: "12px" }}>사용법</p>
            <ul style={{ margin: "4px 0", paddingLeft: "20px" }}>
              <li>카드 클릭으로 이슈 상세 확인</li>
              <li>에이전트별 필터링 가능</li>
              <li>미분류 이슈는 상단에 가로 배치</li>
            </ul>
          </div>
        )}
      </section>
    </div>
  );
}

export function WorkBoardPage({ context }: PluginPageProps) {
  const board = useWorkBoard(context.companyId);

  if (board.loading) {
    return <div style={pageStyle}>미션 보드를 불러오는 중...</div>;
  }
  if (board.error) {
    return <div style={pageStyle}>미션 보드를 불러오지 못했다: {board.error.message}</div>;
  }
  if (!board.data) {
    return <div style={pageStyle}>표시할 데이터가 없다.</div>;
  }

  return (
    <>
      <BoardContent context={context} data={board.data} onRefresh={board.refresh} loading={board.loading} />
      <WorkBoardHelpSection />
    </>
  );
}

export function WorkBoardSidebarLink({ context }: PluginSidebarProps) {
  const href = pluginPagePath(context.companyPrefix);
  const isActive = typeof window !== "undefined" && window.location.pathname === href;

  return (
    <a
      href={href}
      aria-current={isActive ? "page" : undefined}
      className={[
        "flex items-center gap-2.5 px-3 py-2 text-[13px] font-medium transition-colors",
        isActive
          ? "bg-accent text-foreground"
          : "text-foreground/80 hover:bg-accent/50 hover:text-foreground",
      ].join(" ")}
    >
      <span aria-hidden="true">▦</span>
      <span className="truncate">Mission Board</span>
    </a>
  );
}

export function WorkBoardDashboardWidget({ context }: PluginWidgetProps) {
  const board = useWorkBoard(context.companyId);

  if (board.loading) return <div>미션 보드 요약을 불러오는 중...</div>;
  if (board.error) return <div>미션 보드 오류: {board.error.message}</div>;
  if (!board.data) return <div>요약 데이터가 없다.</div>;

  return (
    <section style={{ display: "grid", gap: "12px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "baseline" }}>
        <strong>Mission Board</strong>
        <a href={pluginPagePath(context.companyPrefix)} style={tinyMutedStyle}>Open board</a>
      </div>
      <div style={tinyMutedStyle}>{board.data.weekRange.label}</div>
      <div style={{ display: "grid", gap: "6px" }}>
        <div style={tinyMutedStyle}>미션 {board.data.totals.missions} · 태스크 {board.data.totals.tasks}</div>
        <div style={tinyMutedStyle}>지연 {board.data.totals.overdue} · 진행 {board.data.totals.inProgress} · 대기 {board.data.totals.todo} · 완료 {board.data.totals.done}</div>
      </div>
      <div style={{ display: "grid", gap: "8px" }}>
        {board.data.columns.slice(0, 3).map((column) => (
          <div
            key={column.key}
            style={{
              display: "grid",
              gap: "4px",
              padding: "10px 12px",
              borderRadius: "12px",
              border: "1px solid color-mix(in srgb, var(--border, #d4d4d8) 75%, transparent)",
              background: "color-mix(in srgb, var(--card, #ffffff) 95%, transparent)",
            }}
          >
            <strong style={{ fontSize: "13px" }}>{column.name}</strong>
            <div style={tinyMutedStyle}>미션 {column.missionCount}</div>
          </div>
        ))}
      </div>
    </section>
  );
}
